/**
 * Coverage Scorecard + Core Threshold Gate
 *
 * Purpose:
 * - Generate a small subsystem coverage scorecard from Vitest JSON summary output.
 * - Enforce minimum core coverage thresholds for statements/branches/functions/lines.
 *
 * Key features:
 * - Reads `coverage/coverage-summary.json` generated by Vitest (`json-summary` reporter).
 * - Aggregates metrics for core/events/storage/server and key server contracts.
 * - Writes Markdown + JSON scorecard artifacts to `coverage/`.
 * - Exits non-zero when core thresholds regress below configured minima.
 *
 * Notes on implementation:
 * - Uses weighted totals (`covered` / `total`) across matched files.
 * - Thresholds are intentionally conservative baseline guards and should be ratcheted upward over time.
 *
 * Recent changes:
 * - 2026-02-27: Added Phase 5 quality gate for core coverage and subsystem scorecard publishing.
 */

import fs from 'node:fs';
import path from 'node:path';

const CORE_THRESHOLDS = {
  statements: 68,
  branches: 56,
  functions: 75,
  lines: 69,
};

function normalizePath(filePath) {
  return String(filePath || '').replace(/\\/g, '/');
}

function readCoverageSummary(summaryPath) {
  if (!fs.existsSync(summaryPath)) {
    throw new Error(`Coverage summary not found at ${summaryPath}. Run coverage first.`);
  }

  const raw = fs.readFileSync(summaryPath, 'utf8');
  const parsed = JSON.parse(raw);
  const entries = Object.entries(parsed || {}).filter(([key]) => key !== 'total');

  if (entries.length === 0) {
    throw new Error('Coverage summary contains no file entries.');
  }

  return entries.map(([file, metrics]) => ({
    file: normalizePath(file),
    metrics,
  }));
}

function calculateMetrics(entries, matcher) {
  const matched = entries.filter((entry) => matcher(entry.file));

  const totals = {
    statements: { total: 0, covered: 0, pct: 100 },
    branches: { total: 0, covered: 0, pct: 100 },
    functions: { total: 0, covered: 0, pct: 100 },
    lines: { total: 0, covered: 0, pct: 100 },
    fileCount: matched.length,
  };

  for (const entry of matched) {
    for (const metricName of ['statements', 'branches', 'functions', 'lines']) {
      const metric = entry.metrics?.[metricName];
      totals[metricName].total += Number(metric?.total || 0);
      totals[metricName].covered += Number(metric?.covered || 0);
    }
  }

  for (const metricName of ['statements', 'branches', 'functions', 'lines']) {
    const metric = totals[metricName];
    metric.pct = metric.total > 0 ? (metric.covered / metric.total) * 100 : 100;
  }

  return totals;
}

function formatPct(value) {
  return `${value.toFixed(2)}%`;
}

function buildScorecard(entries) {
  const subsystems = [
    { name: 'core', matcher: (file) => file.includes('/core/') },
    { name: 'core/events', matcher: (file) => file.includes('/core/events/') },
    { name: 'core/storage', matcher: (file) => file.includes('/core/storage/') },
    { name: 'server', matcher: (file) => file.includes('/server/') },
    { name: 'server/api.ts', matcher: (file) => file.endsWith('/server/api.ts') },
    { name: 'server/sse-handler.ts', matcher: (file) => file.endsWith('/server/sse-handler.ts') },
  ];

  return subsystems.map((subsystem) => ({
    subsystem: subsystem.name,
    ...calculateMetrics(entries, subsystem.matcher),
  }));
}

function buildMarkdown(scorecardRows, thresholdStatus) {
  const lines = [];
  lines.push('# Coverage Scorecard');
  lines.push('');
  lines.push(`Generated: ${new Date().toISOString()}`);
  lines.push('');
  lines.push('| Subsystem | Files | Statements | Branches | Functions | Lines |');
  lines.push('|---|---:|---:|---:|---:|---:|');

  for (const row of scorecardRows) {
    lines.push(
      `| ${row.subsystem} | ${row.fileCount} | ${formatPct(row.statements.pct)} | ${formatPct(
        row.branches.pct
      )} | ${formatPct(row.functions.pct)} | ${formatPct(row.lines.pct)} |`
    );
  }

  lines.push('');
  lines.push('## Core Threshold Gate');
  lines.push('');
  lines.push(`- statements >= ${CORE_THRESHOLDS.statements}%`);
  lines.push(`- branches >= ${CORE_THRESHOLDS.branches}%`);
  lines.push(`- functions >= ${CORE_THRESHOLDS.functions}%`);
  lines.push(`- lines >= ${CORE_THRESHOLDS.lines}%`);
  lines.push('');
  lines.push(`Status: **${thresholdStatus.passed ? 'PASS' : 'FAIL'}**`);

  if (!thresholdStatus.passed) {
    lines.push('');
    lines.push('### Regressions');
    for (const failure of thresholdStatus.failures) {
      lines.push(`- ${failure.metric}: ${failure.actual.toFixed(2)}% < ${failure.required.toFixed(2)}%`);
    }
  }

  return `${lines.join('\n')}\n`;
}

function evaluateCoreThresholds(coreRow) {
  if (!coreRow) {
    throw new Error('Core row is missing from scorecard calculations.');
  }

  const checks = [
    { metric: 'statements', actual: coreRow.statements.pct, required: CORE_THRESHOLDS.statements },
    { metric: 'branches', actual: coreRow.branches.pct, required: CORE_THRESHOLDS.branches },
    { metric: 'functions', actual: coreRow.functions.pct, required: CORE_THRESHOLDS.functions },
    { metric: 'lines', actual: coreRow.lines.pct, required: CORE_THRESHOLDS.lines },
  ];

  const failures = checks.filter((check) => check.actual < check.required);

  return {
    passed: failures.length === 0,
    failures,
    checks,
  };
}

function writeArtifacts(outputDir, markdown, payload) {
  fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(path.join(outputDir, 'scorecard.md'), markdown, 'utf8');
  fs.writeFileSync(path.join(outputDir, 'scorecard.json'), JSON.stringify(payload, null, 2), 'utf8');
}

function run() {
  const summaryPath = path.resolve(process.cwd(), 'coverage/coverage-summary.json');
  const outputDir = path.resolve(process.cwd(), 'coverage');

  const entries = readCoverageSummary(summaryPath);
  const scorecardRows = buildScorecard(entries);
  const coreRow = scorecardRows.find((row) => row.subsystem === 'core');
  const thresholdStatus = evaluateCoreThresholds(coreRow);
  const markdown = buildMarkdown(scorecardRows, thresholdStatus);

  const payload = {
    generatedAt: new Date().toISOString(),
    thresholds: CORE_THRESHOLDS,
    thresholdStatus,
    rows: scorecardRows.map((row) => ({
      subsystem: row.subsystem,
      fileCount: row.fileCount,
      statementsPct: Number(row.statements.pct.toFixed(2)),
      branchesPct: Number(row.branches.pct.toFixed(2)),
      functionsPct: Number(row.functions.pct.toFixed(2)),
      linesPct: Number(row.lines.pct.toFixed(2)),
    })),
  };

  writeArtifacts(outputDir, markdown, payload);
  process.stdout.write(markdown);

  if (!thresholdStatus.passed) {
    process.exitCode = 1;
  }
}

run();
